export const skillsDictionary: SkillItem[] = rawSkillsDictionary
  .filter(
    (skill, index, allSkills) =>
      allSkills.findIndex(
        (candidate) =>
          candidate.canonicalName.toLowerCase() ===
          skill.canonicalName.toLowerCase(),
      ) === index,
  )
  .sort((a, b) => a.canonicalName.localeCompare(b.canonicalName));

export const searchableSkillTerms = [
  ...new Set(skillsDictionary.map((skill) => skill.canonicalName)),
] as string[];

export const allSearchableSkillTerms = [
  ...new Set(
    skillsDictionary.flatMap((skill) => [
      skill.canonicalName,
      ...skill.aliases,
      ...(skill.searchKeywords ?? []),
    ]),
  ),
] as string[];
